    16→    folder?: string;
    17→    tags?: string[];
    18→  };
    19→}
    20→
    21→export interface GraphEdge {
    22→  source: string; // Node ID
    23→  target: string; // Node ID
    24→  type: 'backlink' | 'tag';
    25→  strength: number; // For force simulation
    26→}
    27→
    28→export interface GraphData {
    29→  nodes: GraphNode[];
    30→  edges: GraphEdge[];
    31→}
    32→
    33→export interface GraphFilters {
    34→  searchQuery?: string;
    35→  selectedTags?: string[];
    36→  selectedFolders?: string[];
    37→  hideOrphans?: boolean;
    38→}
    39→
    40→/**
    41→ * Build graph data from notes
    42→ */
    43→export function buildGraphData(
    44→  notes: Record<string, Note>,
    45→  filters: GraphFilters = {}
    46→): GraphData {
    47→  const nodes: GraphNode[] = [];
    48→  const edges: GraphEdge[] = [];
    49→  const nodeMap = new Map<string, GraphNode>();
    50→  const tagNodeMap = new Map<string, GraphNode>();
    51→
    52→  // Get all notes as array
    53→  const notesArray = Object.values(notes);
    54→
    55→  // Filter notes based on search/folder filters
    56→  let filteredNotes = notesArray;
    57→
    58→  if (filters.searchQuery) {
    59→    const query = filters.searchQuery.toLowerCase();
    60→    filteredNotes = filteredNotes.filter(
    61→      (note) =>
    62→        note.title.toLowerCase().includes(query) ||
    63→        note.content.toLowerCase().includes(query)
    64→    );
    65→  }
    66→
    67→  if (filters.selectedFolders && filters.selectedFolders.length > 0) {
    68→    filteredNotes = filteredNotes.filter((note) =>
    69→      filters.selectedFolders!.includes(note.folderId || 'root')
    70→    );
    71→  }
    72→
    73→  // Create note nodes
    74→  filteredNotes.forEach((note) => {
    75→    const node: GraphNode = {
    76→      id: note.id,
    77→      type: 'note',
    78→      label: note.title || 'Untitled',
    79→      color: 'var(--accent-cyan)', // Semantic token for notes
    80→      size: 10, // Base size, will be updated based on connections
    81→      metadata: {
    82→        createdAt: note.createdAt.toString(),
    83→        folder: note.folderId || undefined,
    84→        tags: note.tags || [],
    85→      },
    86→    };
    87→    nodes.push(node);
    88→    nodeMap.set(note.id, node);
    89→  });
    90→
    91→  // Create tag nodes and tag edges
    92→  const allTags = new Set<string>();
    93→  filteredNotes.forEach((note) => {
    94→    if (note.tags && note.tags.length > 0) {
    95→      note.tags.forEach((tag) => allTags.add(tag));
    96→    }
    97→  });
    98→
    99→  // Filter by selected tags if provided
   100→  let tagsToInclude = Array.from(allTags);
   101→  if (filters.selectedTags && filters.selectedTags.length > 0) {
   102→    tagsToInclude = tagsToInclude.filter((tag) =>
   103→      filters.selectedTags!.includes(tag)
   104→    );
   105→  }
   106→
   107→  tagsToInclude.forEach((tag) => {
   108→    const tagNode: GraphNode = {
   109→      id: `tag:${tag}`,
   110→      type: 'tag',
