              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="w-full pl-10 pr-4 py-2 rounded-lg border border-border-light dark:border-border-dark bg-surface-light-base dark:bg-surface-dark-base text-text-light-primary dark:text-text-dark-primary focus:outline-none focus:ring-2 focus:ring-accent-magenta"
            />
          </div>

          {/* Hide Orphans Toggle */}
          <label className="flex items-center gap-2 cursor-pointer">
            <input
              type="checkbox"
              checked={hideOrphans}
              onChange={(e) => setHideOrphans(e.target.checked)}
              className="w-4 h-4 rounded border-border-light dark:border-border-dark text-accent-magenta focus:ring-accent-magenta"
            />
            <span className="text-sm text-text-light-secondary dark:text-text-dark-secondary">
              Hide orphans
            </span>
          </label>

          {/* Stats */}
          <div className="text-sm text-text-light-tertiary dark:text-text-dark-tertiary">
            {graphData.nodes.length} nodes · {graphData.edges.length} connections
          </div>
        </div>

        {/* Graph or Empty State */}
        {!hasNotes ? (
          <div className="flex-1 flex items-center justify-center">
            <div className="text-center">
              <p className="text-text-light-secondary dark:text-text-dark-secondary mb-2">
                No notes yet
              </p>
              <p className="text-sm text-text-light-tertiary dark:text-text-dark-tertiary">
                Create some notes with backlinks to see your knowledge graph
              </p>
            </div>
          </div>
        ) : graphData.nodes.length === 0 ? (
          <div className="flex-1 flex items-center justify-center">
            <div className="text-center">
              <p className="text-text-light-secondary dark:text-text-dark-secondary mb-2">
                No notes match your filters
              </p>
              <p className="text-sm text-text-light-tertiary dark:text-text-dark-tertiary">
                Try adjusting your search or showing orphan notes
              </p>
            </div>
          </div>
        ) : (
          <div className="flex-1 overflow-hidden">
            <GraphCanvas data={graphData} onNodeClick={handleNodeClick} />
          </div>
        )}

        {/* Legend */}
        <div className="flex items-center gap-6 text-xs text-text-light-tertiary dark:text-text-dark-tertiary">
          <div className="flex items-center gap-2">
            <div className="w-3 h-3 rounded-full bg-[var(--accent-cyan)]" />
            <span>Notes</span>
          </div>
          <div className="flex items-center gap-2">
            <div className="w-3 h-3 rounded-full bg-[var(--accent-magenta)]" />
            <span>Tags</span>
          </div>
          <div className="flex items-center gap-2">
            <div className="w-8 h-0.5 bg-[var(--accent-cyan)]" />
            <span>Backlinks</span>
          </div>
          <div className="flex items-center gap-2">
            <div className="w-8 h-0.5 bg-[var(--border-light)] dark:bg-[var(--border-dark)]" />
            <span>Tags</span>
          </div>
        </div>

        {/* Instructions */}
        <div className="text-xs text-text-light-tertiary dark:text-text-dark-tertiary">
          <span className="font-medium">Tip:</span> Drag nodes to reposition · Scroll to zoom · Click node to open
        </div>
      </div>
    </div>
  );
}
